1302 /// Matches canonical form of isnan, fcmp ord x, 0
1303 static bool matchIsNotNaN(FCmpInst::Predicate P, Value *LHS, Value *RHS) {
1304   return P == FCmpInst::FCMP_ORD && match(RHS, m_AnyZeroFP());
1305 }
