1307 /// Matches fcmp u__ x, +/-inf
1308 static bool matchUnorderedInfCompare(FCmpInst::Predicate P, Value *LHS,
1309                                      Value *RHS) {
1310   return FCmpInst::isUnordered(P) && match(RHS, m_Inf());
1311 }
