4343 bool FCmpInst::compare(const APFloat &LHS, const APFloat &RHS,
4344                        FCmpInst::Predicate Pred) {
4345   APFloat::cmpResult R = LHS.compare(RHS);
4346   switch (Pred) {
4347   default:
4348     llvm_unreachable("Invalid FCmp Predicate");
4349   case FCmpInst::FCMP_FALSE:
4350     return false;
4351   case FCmpInst::FCMP_TRUE:
4352     return true;
4353   case FCmpInst::FCMP_UNO:
4354     return R == APFloat::cmpUnordered;
4355   case FCmpInst::FCMP_ORD:
4356     return R != APFloat::cmpUnordered;
4357   case FCmpInst::FCMP_UEQ:
4358     return R == APFloat::cmpUnordered || R == APFloat::cmpEqual;
4359   case FCmpInst::FCMP_OEQ:
4360     return R == APFloat::cmpEqual;
4361   case FCmpInst::FCMP_UNE:
4362     return R != APFloat::cmpEqual;
4363   case FCmpInst::FCMP_ONE:
4364     return R == APFloat::cmpLessThan || R == APFloat::cmpGreaterThan;
4365   case FCmpInst::FCMP_ULT:
4366     return R == APFloat::cmpUnordered || R == APFloat::cmpLessThan;
4367   case FCmpInst::FCMP_OLT:
4368     return R == APFloat::cmpLessThan;
4369   case FCmpInst::FCMP_UGT:
4370     return R == APFloat::cmpUnordered || R == APFloat::cmpGreaterThan;
4371   case FCmpInst::FCMP_OGT:
4372     return R == APFloat::cmpGreaterThan;
4373   case FCmpInst::FCMP_ULE:
4374     return R != APFloat::cmpGreaterThan;
4375   case FCmpInst::FCMP_OLE:
4376     return R == APFloat::cmpLessThan || R == APFloat::cmpEqual;
4377   case FCmpInst::FCMP_UGE:
4378     return R != APFloat::cmpLessThan;
4379   case FCmpInst::FCMP_OGE:
4380     return R == APFloat::cmpGreaterThan || R == APFloat::cmpEqual;
4381   }
4382 }
